public class StonePile {
    public static List<Integer> makeAPile(int n) {
        List<Integer> stones = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            if (i == 0) {
                stones.add(n);
            } else {
                if (stones.get(i - 1) % 2 == 0) { // If the last level's stones are even
                    stones.add(stones.get(i - 1) + 2); // next even number
                } else { // If the last level's stones are odd
                    stones.add(stones.get(i - 1) + 2); // next odd number
                }
            }
        }
        return stones;
    }
}
